import React, { useState, useEffect } from 'react';
import { Container, Row, Col, Card, Form, Button, Alert, Table } from 'react-bootstrap';
import { useAuth } from '../context/AuthContext';

const MealLog = () => {
  const { token, authFetch } = useAuth();
  const [meals, setMeals] = useState([]);
  const [formData, setFormData] = useState({
    meal_type: 'breakfast',
    food_name: '',
    serving_size: 100,
    calories: '',
    protein: '',
    carbs: '',
    fats: ''
  });
  const [suggestions, setSuggestions] = useState([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const mealTypes = ['breakfast', 'lunch', 'dinner', 'snack'];

  useEffect(() => {
    loadTodayMeals();
  }, []);

  const searchFoods = async (query) => {
    if (!query || query.length < 2) {
      setSuggestions([]);
      setShowSuggestions(false);
      return;
    }

    try {
      const res = await authFetch(`/api/foods/search?q=${encodeURIComponent(query)}`);
      if (res.ok) {
        const data = await res.json();
        setSuggestions(data.foods || []);
        setShowSuggestions(true);
      }
    } catch (err) {
      console.error('Failed to search foods:', err);
    }
  };

  const selectFood = async (food) => {
    try {
      const res = await authFetch(`/api/foods/nutrition?food=${encodeURIComponent(food)}&serving=${formData.serving_size}`);
      if (res.ok) {
        const data = await res.json();
        const nutrition = data.nutrition;

        setFormData({
          ...formData,
          food_name: food,
          calories: nutrition.calories,
          protein: nutrition.protein,
          carbs: nutrition.carbs,
          fats: nutrition.fats
        });
        setShowSuggestions(false);
        setSuggestions([]);
      }
    } catch (err) {
      console.error('Failed to get nutrition:', err);
    }
  };

  // Close suggestions when clicking outside
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (showSuggestions && !event.target.closest('.position-relative')) {
        setShowSuggestions(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [showSuggestions]);

  const loadTodayMeals = async () => {
    try {
      const today = new Date().toISOString().split('T')[0];
      const res = await authFetch(`/api/diet-log?date=${today}`);
      if (res.ok) {
        const data = await res.json();
        setMeals(data.logs || []);
      }
    } catch (err) {
      console.error('Failed to load meals:', err);
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });

    // Trigger food search when food name changes
    if (name === 'food_name') {
      searchFoods(value);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const mealData = {
        ...formData,
        calories: parseInt(formData.calories) || 0,
        protein: parseFloat(formData.protein) || 0,
        carbs: parseFloat(formData.carbs) || 0,
        fats: parseFloat(formData.fats) || 0,
        date: new Date().toISOString().split('T')[0]
      };

      const res = await authFetch('/api/diet-log', {
        method: 'POST',
        body: mealData
      });

      if (res.ok) {
        setFormData({
          meal_type: 'breakfast',
          food_name: '',
          calories: '',
          protein: '',
          carbs: '',
          fats: ''
        });
        loadTodayMeals();
      } else {
        const data = await res.json();
        setError(data.error || 'Failed to log meal');
      }
    } catch (err) {
      setError('Failed to log meal. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const getTotalNutrients = () => {
    return meals.reduce((totals, meal) => ({
      calories: totals.calories + (meal.calories || 0),
      protein: totals.protein + (meal.protein || 0),
      carbs: totals.carbs + (meal.carbs || 0),
      fats: totals.fats + (meal.fats || 0)
    }), { calories: 0, protein: 0, carbs: 0, fats: 0 });
  };

  const totals = getTotalNutrients();

  return (
    <Container className="mt-4">
      <h2 className="mb-4">Smart Meal Logging</h2>

      <Alert variant="info" className="mb-4">
        <h6 className="alert-heading">🍽️ Auto-Calculate Nutrition!</h6>
        <p className="mb-2">
          <strong>Simply type a food name</strong> (e.g., "rice", "chicken", "apple")<br/>
          <strong>Select from suggestions</strong> to auto-fill calories, protein, carbs, fats<br/>
          <strong>Adjust serving size</strong> if needed (default: 100g)
        </p>
        <hr />
        <p className="mb-0 text-muted small">
          Database includes Indian foods like chapati, dal, samosa, paneer tikka, idli, dosa, and common foods.
        </p>
      </Alert>

      <Row>
        <Col md={4}>
          <Card>
            <Card.Header>
              <h5 className="mb-0">Log Your Meal</h5>
            </Card.Header>
            <Card.Body>
              {error && <Alert variant="danger">{error}</Alert>}

              <Form onSubmit={handleSubmit}>
                <Form.Group className="mb-3">
                  <Form.Label>Meal Type</Form.Label>
                  <Form.Select name="meal_type" value={formData.meal_type} onChange={handleChange}>
                    {mealTypes.map(type => (
                      <option key={type} value={type}>
                        {type.charAt(0).toUpperCase() + type.slice(1)}
                      </option>
                    ))}
                  </Form.Select>
                </Form.Group>

                <Form.Group className="mb-3">
                  <Form.Label>Food Name</Form.Label>
                  <div className="position-relative">
                    <Form.Control
                      type="text"
                      name="food_name"
                      value={formData.food_name}
                      onChange={handleChange}
                      placeholder="e.g., Rice, Chicken, Apple"
                      required
                      autoComplete="off"
                    />
                    {showSuggestions && suggestions.length > 0 && (
                      <div className="position-absolute w-100 bg-white border rounded mt-1 shadow" 
                           style={{ zIndex: 1000, maxHeight: '200px', overflowY: 'auto', cursor: 'pointer' }}>
                        {suggestions.map((food, index) => (
                          <div
                            key={index}
                            className="p-2 border-bottom hover:bg-light"
                            onClick={() => selectFood(food)}
                            onMouseDown={(e) => e.preventDefault()}
                            style={{ 
                              cursor: 'pointer',
                              backgroundColor: formData.food_name.toLowerCase() === food.toLowerCase() ? '#f8f9fa' : 'transparent'
                            }}
                          >
                            <strong>{food.charAt(0).toUpperCase() + food.slice(1)}</strong>
                            <small className="text-muted d-block">
                              {FOOD_DATABASE[food.toLowerCase()] ? 
                                `${FOOD_DATABASE[food.toLowerCase()].calories} cal per 100g` : 
                                'Custom food'
                              }
                            </small>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                </Form.Group>

                <Row>
                  <Col md={4}>
                    <Form.Group className="mb-3">
                      <Form.Label>Serving Size (g)</Form.Label>
                      <Form.Control
                        type="number"
                        name="serving_size"
                        value={formData.serving_size}
                        onChange={handleChange}
                        placeholder="100"
                        min="1"
                        max="1000"
                      />
                    </Form.Group>
                  </Col>
                  <Col md={2}>
                    <Form.Group className="mb-3">
                      <Form.Label>Calories</Form.Label>
                      <Form.Control
                        type="number"
                        name="calories"
                        value={formData.calories}
                        onChange={handleChange}
                        placeholder="Auto-calculated"
                        readOnly
                      />
                    </Form.Group>
                  </Col>
                  <Col md={2}>
                    <Form.Group className="mb-3">
                      <Form.Label>Protein (g)</Form.Label>
                      <Form.Control
                        type="number"
                        step="0.1"
                        name="protein"
                        value={formData.protein}
                        onChange={handleChange}
                        placeholder="Auto-calculated"
                        readOnly
                      />
                    </Form.Group>
                  </Col>
                  <Col md={2}>
                    <Form.Group className="mb-3">
                      <Form.Label>Carbs (g)</Form.Label>
                      <Form.Control
                        type="number"
                        step="0.1"
                        name="carbs"
                        value={formData.carbs}
                        onChange={handleChange}
                        placeholder="Auto-calculated"
                        readOnly
                      />
                    </Form.Group>
                  </Col>
                  <Col md={2}>
                    <Form.Group className="mb-3">
                      <Form.Label>Fats (g)</Form.Label>
                      <Form.Control
                        type="number"
                        step="0.1"
                        name="fats"
                        value={formData.fats}
                        onChange={handleChange}
                        placeholder="Auto-calculated"
                        readOnly
                      />
                    </Form.Group>
                  </Col>
                </Row>

                <Button variant="primary" type="submit" className="w-100" disabled={loading}>
                  {loading ? 'Logging...' : 'Log Meal'}
                </Button>
              </Form>
            </Card.Body>
          </Card>
        </Col>

        <Col md={8}>
          <Card>
            <Card.Header>
              <h5 className="mb-0">Today's Meals</h5>
            </Card.Header>
            <Card.Body>
              <div className="mb-4">
                <h6>Daily Totals</h6>
                <Row>
                  <Col><strong>Calories:</strong> {totals.calories}</Col>
                  <Col><strong>Protein:</strong> {totals.protein.toFixed(1)}g</Col>
                  <Col><strong>Carbs:</strong> {totals.carbs.toFixed(1)}g</Col>
                  <Col><strong>Fats:</strong> {totals.fats.toFixed(1)}g</Col>
                </Row>
              </div>

              {meals.length > 0 ? (
                <Table striped hover>
                  <thead>
                    <tr>
                      <th>Meal</th>
                      <th>Food</th>
                      <th>Calories</th>
                      <th>Protein</th>
                      <th>Carbs</th>
                      <th>Fats</th>
                    </tr>
                  </thead>
                  <tbody>
                    {meals.map((meal, index) => (
                      <tr key={index}>
                        <td>{meal.meal_type}</td>
                        <td>{meal.food_name}</td>
                        <td>{meal.calories}</td>
                        <td>{meal.protein}g</td>
                        <td>{meal.carbs}g</td>
                        <td>{meal.fats}g</td>
                      </tr>
                    ))}
                  </tbody>
                </Table>
              ) : (
                <p className="text-muted">No meals logged today. Start logging your meals to see them here!</p>
              )}
            </Card.Body>
          </Card>
        </Col>
      </Row>
    </Container>
  );
};

export default MealLog;
